"use client"

import * as React from "react"
import {
  IconArmchair,
  IconArrowRight,
  IconBus,
  IconClock,
  IconMapPin,
  IconMoon,
  IconSun,
  IconWoman,
  IconToiletPaper,
  IconPlugConnected,
} from "@tabler/icons-react"

import {
  AmountBreakdown,
  Badge,
  Button,
  Card,
  PageHeader,
  RadioCard,
  RadioCardGroup,
  SeatMap,
  Select,
  Separator,
  Stepper,
  Tag,
  TicketStub,
  type AmountLine,
  type StepperStep,
} from "@gunjo/ui"

import {
  alightingStops,
  boardingStops,
  bookingFee,
  departures,
  discountOptions,
  findPlan,
  peakSurcharge,
  type CoachAttr,
  type PlanId,
  type Stop,
} from "./data"

const yen = (n: number) => `¥${n.toLocaleString("ja-JP")}`

type StepKey = "plan" | "seat" | "board" | "review" | "done"

const STEP_ORDER: { key: StepKey; label: string }[] = [
  { key: "plan", label: "便・プラン" },
  { key: "seat", label: "座席" },
  { key: "board", label: "乗車地" },
  { key: "review", label: "確認" },
  { key: "done", label: "完了" },
]

/** Build the Stepper steps from the active step. */
function buildSteps(active: StepKey): StepperStep[] {
  const activeIdx = STEP_ORDER.findIndex((s) => s.key === active)
  return STEP_ORDER.map((s, i) => ({
    label: s.label,
    state: i < activeIdx ? "completed" : i === activeIdx ? "current" : "upcoming",
  }))
}

// ---- Coach attribute legend (the layer SeatMap can't express) --------------

const ATTR_META: Record<
  CoachAttr,
  { icon: React.ComponentType<{ className?: string }>; tone: string }
> = {
  女性専用: { icon: IconWoman, tone: "text-pink-600" },
  トイレ付近: { icon: IconToiletPaper, tone: "text-sky-600" },
  コンセント: { icon: IconPlugConnected, tone: "text-amber-600" },
  最前列: { icon: IconArmchair, tone: "text-emerald-600" },
  補助席: { icon: IconArmchair, tone: "text-muted-foreground" },
}

function CoachLegend({ attrs }: { attrs: CoachAttr[] }) {
  return (
    <ul className="flex flex-wrap gap-x-4 gap-y-1.5 text-[11px] text-muted-foreground" aria-label="座席属性の凡例">
      {attrs.map((a) => {
        const Icon = ATTR_META[a].icon
        return (
          <li key={a} className="inline-flex items-center gap-1">
            <Icon className={`size-3.5 ${ATTR_META[a].tone}`} aria-hidden="true" />
            {a}
          </li>
        )
      })}
    </ul>
  )
}

export default function HighwayBusBookingPage() {
  const [step, setStep] = React.useState<StepKey>("plan")
  const [planId, setPlanId] = React.useState<PlanId>(departures[0].defaultPlanId)
  const [seatIds, setSeatIds] = React.useState<string[]>([])
  const [boardId, setBoardId] = React.useState<string>(boardingStops[0].id)
  const [alightId, setAlightId] = React.useState<string>(alightingStops[0].id)
  const [discountId, setDiscountId] = React.useState<string>(discountOptions[0].id)

  const { departure, plan } = React.useMemo(() => findPlan(planId), [planId])
  const board = boardingStops.find((s) => s.id === boardId) ?? boardingStops[0]
  const alight = alightingStops.find((s) => s.id === alightId) ?? alightingStops[0]
  const discount = discountOptions.find((d) => d.id === discountId) ?? discountOptions[0]
  const isPeak = departure.daynight === "夜行" // 夜行=金曜発 demo flag

  // When switching plan (and thus coach), drop seat picks that no longer exist.
  React.useEffect(() => {
    setSeatIds((prev) => prev.filter((id) => plan.seats.some((s) => s.id === id && s.state !== "occupied")))
  }, [plan])

  // ---- Fare math ----
  const pax = Math.max(seatIds.length, 1)
  const seatFees = seatIds.reduce((sum, id) => {
    const s = plan.seats.find((x) => x.id === id)
    return sum + (s?.fee ?? 0)
  }, 0)

  const fareLines: AmountLine[] = [
    { label: `大人運賃 × ${pax}名`, amount: plan.baseFare * pax, note: `${plan.name}（${plan.rowTag}）` },
  ]
  if (discount.amount !== 0) {
    fareLines.push({ label: `${discount.label} × ${pax}名`, amount: Math.abs(discount.amount) * pax, kind: "subtract", note: discount.note })
  }
  if (isPeak) {
    fareLines.push({ label: peakSurcharge.label, amount: peakSurcharge.amount * pax, note: peakSurcharge.note })
  }
  if (seatFees > 0) {
    fareLines.push({ label: "座席指定料（最前列など）", amount: seatFees, note: "選択座席ごとの加算" })
  }
  fareLines.push({ label: bookingFee.label, amount: bookingFee.amount })

  const total =
    plan.baseFare * pax +
    discount.amount * pax +
    (isPeak ? peakSurcharge.amount * pax : 0) +
    seatFees +
    bookingFee.amount

  const reservationNo = `GJ${departure.id.slice(-2).toUpperCase()}-${(seatIds[0] ?? "000")}-2406`

  // ---- Navigation guards ----
  const canLeaveSeat = seatIds.length >= 1
  const goNext = () => {
    const idx = STEP_ORDER.findIndex((s) => s.key === step)
    const next = STEP_ORDER[idx + 1]
    if (next) setStep(next.key)
  }
  const goBack = () => {
    const idx = STEP_ORDER.findIndex((s) => s.key === step)
    const prev = STEP_ORDER[idx - 1]
    if (prev) setStep(prev.key)
  }

  const headerTitle =
    step === "plan"
      ? "便・プランを選ぶ"
      : step === "seat"
        ? "座席を選ぶ"
        : step === "board"
          ? "乗車地・降車地"
          : step === "review"
            ? "予約内容の確認"
            : "予約完了"

  return (
    <div className="mx-auto flex min-h-dvh w-full max-w-[420px] flex-col bg-background pb-28">
      <PageHeader
        title={headerTitle}
        subtitle="バスタ新宿 → 大阪（梅田／なんば）"
        align="center"
        onBack={step === "plan" ? undefined : goBack}
      />

      {/* Progress */}
      <Stepper steps={buildSteps(step)} aria-label="予約ステップ" className="border-b border-border !p-3" />

      <main className="flex flex-1 flex-col gap-5 px-4 py-4">
        {step === "plan" && (
          <PlanStep
            planId={planId}
            onSelect={(id) => {
              setPlanId(id)
              setSeatIds([])
            }}
          />
        )}

        {step === "seat" && (
          <SeatStep
            seatIds={seatIds}
            onToggle={(id) =>
              setSeatIds((prev) => (prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]))
            }
            plan={plan}
            departure={departure}
          />
        )}

        {step === "board" && (
          <BoardStep
            boardId={boardId}
            alightId={alightId}
            discountId={discountId}
            onBoard={setBoardId}
            onAlight={setAlightId}
            onDiscount={setDiscountId}
          />
        )}

        {step === "review" && (
          <ReviewStep
            departure={departure}
            planName={`${plan.name}（${plan.rowTag}）`}
            seatIds={seatIds}
            board={board}
            alight={alight}
            fareLines={fareLines}
            total={total}
          />
        )}

        {step === "done" && (
          <DoneStep
            reservationNo={reservationNo}
            departure={departure}
            seatIds={seatIds}
            board={board}
            alight={alight}
            total={total}
          />
        )}
      </main>

      {/* Sticky fare + CTA bar */}
      {step !== "done" && (
        <footer className="fixed inset-x-0 bottom-0 z-20 mx-auto w-full max-w-[420px] border-t border-border bg-background/95 px-4 py-3 pb-[max(0.75rem,env(safe-area-inset-bottom))] backdrop-blur">
          <div className="flex items-center justify-between gap-3">
            <div className="min-w-0">
              <p className="text-[11px] text-muted-foreground">合計（{pax}名）</p>
              <p className="text-lg font-bold tabular-nums text-foreground">{yen(total)}</p>
            </div>
            <Button
              size="lg"
              variant="primary"
              className="min-h-11 flex-1 justify-center"
              disabled={step === "seat" && !canLeaveSeat}
              onClick={goNext}
            >
              {step === "review" ? "予約を確定する" : step === "board" ? "確認へ進む" : "次へ"}
              <IconArrowRight className="size-4" aria-hidden="true" />
            </Button>
          </div>
          {step === "seat" && !canLeaveSeat && (
            <p className="mt-1.5 text-center text-[11px] text-warning-strong" role="status">
              座席を1席以上えらんでください
            </p>
          )}
        </footer>
      )}
    </div>
  )
}

// ---------------------------------------------------------------------------
// Step 1 — 便・プラン選択
// ---------------------------------------------------------------------------

function PlanStep({ planId, onSelect }: { planId: PlanId; onSelect: (id: PlanId) => void }) {
  return (
    <RadioCardGroup
      value={planId}
      onValueChange={(v) => onSelect(v as PlanId)}
      aria-label="便と運賃プラン"
      className="gap-4"
    >
      {departures.map((d) => (
        <section key={d.id} aria-label={`${d.operator} ${d.service}`} className="flex flex-col gap-2">
          <div className="flex items-center gap-2 px-0.5">
            {d.daynight === "夜行" ? (
              <IconMoon className="size-4 text-indigo-500" aria-hidden="true" />
            ) : (
              <IconSun className="size-4 text-amber-500" aria-hidden="true" />
            )}
            <span className="text-sm font-semibold text-foreground">{d.operator}</span>
            <Badge variant="secondary">{d.daynight}</Badge>
          </div>
          <div className="flex items-center gap-2 px-0.5 text-xs tabular-nums text-muted-foreground">
            <IconClock className="size-3.5" aria-hidden="true" />
            <span className="font-medium text-foreground">{d.depTime}</span>
            発
            <IconArrowRight className="size-3" aria-hidden="true" />
            <span className="font-medium text-foreground">{d.arrTime}</span>
            {d.arrNextDay ? "着（翌）" : "着"}
            <span>・所要 {d.duration}</span>
          </div>
          {d.plans.map((p) => (
            <RadioCard
              key={p.id}
              value={p.id}
              leading={<IconBus className="size-5 text-primary" aria-hidden="true" />}
              tags={
                <>
                  <Tag variant="outline" size="sm">
                    {p.rowTag}
                  </Tag>
                  {p.highlight ? (
                    <Tag variant="default" size="sm">
                      {p.highlight}
                    </Tag>
                  ) : null}
                </>
              }
              title={p.name}
              description={p.conditions}
              price={
                <span>
                  {yen(p.baseFare)}
                  <span className="ml-0.5 text-[11px] font-normal text-muted-foreground">/人〜</span>
                </span>
              }
              highlight={p.badges[0]}
            />
          ))}
        </section>
      ))}
    </RadioCardGroup>
  )
}

// ---------------------------------------------------------------------------
// Step 2 — 座席選択
// ---------------------------------------------------------------------------

function SeatStep({
  seatIds,
  onToggle,
  plan,
  departure,
}: {
  seatIds: string[]
  onToggle: (id: string) => void
  plan: ReturnType<typeof findPlan>["plan"]
  departure: ReturnType<typeof findPlan>["departure"]
}) {
  const legendAttrs = React.useMemo<CoachAttr[]>(() => {
    const set = new Set<CoachAttr>()
    for (const s of plan.seats) {
      if (!s.type) continue
      for (const part of s.type.split("・")) set.add(part as CoachAttr)
    }
    return [...set]
  }, [plan])

  return (
    <div className="flex flex-col gap-4">
      <Card className="flex-row items-center gap-3 p-3">
        <IconBus className="size-5 shrink-0 text-primary" aria-hidden="true" />
        <div className="min-w-0 flex-1">
          <p className="truncate text-sm font-semibold text-foreground">
            {departure.operator}・{plan.name}
          </p>
          <p className="truncate text-xs text-muted-foreground">
            {plan.rowTag}／{departure.daynight}・1号車
          </p>
        </div>
        <Badge variant="info">最大2席</Badge>
      </Card>

      <div className="rounded-lg border border-border bg-card p-3">
        {/* 進行方向 marker — SeatMap has no "front of coach" affordance, hand-rolled */}
        <div className="mb-2 flex items-center justify-center gap-1.5 text-[11px] font-medium text-muted-foreground">
          <IconArrowRight className="size-3.5 -rotate-90" aria-hidden="true" />
          進行方向（前方）・運転席
        </div>
        <SeatMap
          columns={plan.columns}
          seats={plan.seats}
          selectedIds={seatIds}
          maxSelectable={2}
          onToggle={onToggle}
          formatFee={yen}
          label={`${plan.name}の座席表`}
        />
        {legendAttrs.length > 0 && (
          <>
            <Separator className="my-3" />
            <CoachLegend attrs={legendAttrs} />
          </>
        )}
      </div>

      <div aria-live="polite" className="px-0.5 text-sm">
        {seatIds.length === 0 ? (
          <p className="text-muted-foreground">座席をタップして選択してください（1〜2席）。</p>
        ) : (
          <p className="text-foreground">
            選択中の座席：
            <span className="font-semibold tabular-nums">{seatIds.join("・")}</span>
          </p>
        )}
      </div>
    </div>
  )
}

// ---------------------------------------------------------------------------
// Step 3 — 乗車地・降車地・割引
// ---------------------------------------------------------------------------

function StopRadioList({
  legend,
  stops,
  value,
  onChange,
  name,
}: {
  legend: string
  stops: Stop[]
  value: string
  onChange: (id: string) => void
  name: string
}) {
  return (
    <fieldset className="flex flex-col gap-2">
      <legend className="mb-1 flex items-center gap-1.5 text-sm font-semibold text-foreground">
        <IconMapPin className="size-4 text-primary" aria-hidden="true" />
        {legend}
      </legend>
      {stops.map((s) => {
        const checked = value === s.id
        return (
          <label
            key={s.id}
            className={`flex min-h-11 cursor-pointer items-center gap-3 rounded-lg border p-3 transition-colors ${
              checked ? "border-primary ring-1 ring-primary" : "border-border hover:border-primary/50"
            }`}
          >
            <input
              type="radio"
              name={name}
              value={s.id}
              checked={checked}
              onChange={() => onChange(s.id)}
              className="size-4 accent-[var(--primary)]"
            />
            <span className="min-w-0 flex-1">
              <span className="block truncate text-sm font-medium text-foreground">{s.name}</span>
              {s.note ? <span className="block truncate text-xs text-muted-foreground">{s.note}</span> : null}
            </span>
            <span className="shrink-0 text-sm font-semibold tabular-nums text-foreground">
              {s.nextDay ? "翌 " : ""}
              {s.time}
            </span>
          </label>
        )
      })}
    </fieldset>
  )
}

function BoardStep({
  boardId,
  alightId,
  discountId,
  onBoard,
  onAlight,
  onDiscount,
}: {
  boardId: string
  alightId: string
  discountId: string
  onBoard: (id: string) => void
  onAlight: (id: string) => void
  onDiscount: (id: string) => void
}) {
  return (
    <div className="flex flex-col gap-6">
      <StopRadioList legend="乗車地" stops={boardingStops} value={boardId} onChange={onBoard} name="board" />
      <Separator />
      <StopRadioList legend="降車地" stops={alightingStops} value={alightId} onChange={onAlight} name="alight" />
      <Separator />
      <div className="flex flex-col gap-1.5">
        <Select
          label="割引の適用"
          description="学割は乗車時に学生証の提示が必要です。"
          value={discountId}
          onChange={(e) => onDiscount(e.target.value)}
        >
          {discountOptions.map((d) => (
            <option key={d.id} value={d.id}>
              {d.label}
              {d.amount !== 0 ? `（${d.amount > 0 ? "+" : "−"}¥${Math.abs(d.amount).toLocaleString("ja-JP")}）` : ""}
            </option>
          ))}
        </Select>
      </div>
    </div>
  )
}

// ---------------------------------------------------------------------------
// Step 4 — 確認
// ---------------------------------------------------------------------------

function SummaryRow({ label, value }: { label: string; value: React.ReactNode }) {
  return (
    <div className="flex items-baseline justify-between gap-4 py-1.5">
      <dt className="shrink-0 text-xs text-muted-foreground">{label}</dt>
      <dd className="min-w-0 text-right text-sm font-medium text-foreground">{value}</dd>
    </div>
  )
}

function ReviewStep({
  departure,
  planName,
  seatIds,
  board,
  alight,
  fareLines,
  total,
}: {
  departure: ReturnType<typeof findPlan>["departure"]
  planName: string
  seatIds: string[]
  board: Stop
  alight: Stop
  fareLines: AmountLine[]
  total: number
}) {
  return (
    <div className="flex flex-col gap-5">
      <Card className="p-4">
        <h2 className="mb-2 text-sm font-semibold text-foreground">便・席</h2>
        <dl>
          <SummaryRow label="運行会社" value={departure.operator} />
          <SummaryRow label="便" value={`${departure.service}・${departure.daynight}`} />
          <SummaryRow label="プラン" value={planName} />
          <SummaryRow
            label="座席"
            value={seatIds.length ? <span className="tabular-nums">{seatIds.join("・")}</span> : "—"}
          />
        </dl>
      </Card>

      <Card className="p-4">
        <h2 className="mb-2 text-sm font-semibold text-foreground">乗車区間</h2>
        <dl>
          <SummaryRow
            label="乗車地"
            value={
              <span>
                {board.name}
                <span className="ml-1 tabular-nums text-muted-foreground">{board.time}</span>
              </span>
            }
          />
          <SummaryRow
            label="降車地"
            value={
              <span>
                {alight.name}
                <span className="ml-1 tabular-nums text-muted-foreground">
                  {alight.nextDay ? "翌 " : ""}
                  {alight.time}
                </span>
              </span>
            }
          />
        </dl>
      </Card>

      <Card className="p-4">
        <h2 className="mb-2 text-sm font-semibold text-foreground">運賃内訳</h2>
        <AmountBreakdown
          lines={fareLines}
          total={{ label: "お支払金額", amount: total }}
          formula="大人運賃 ± 割引/繁忙期 ＋ 座席指定料 ＋ 予約手数料 = お支払金額"
          formatValue={yen}
        />
      </Card>

      <p className="px-1 text-xs text-muted-foreground">
        「予約を確定する」を押すと予約番号が発行されます。出発前日までは
        <span className="font-medium text-foreground"> キャンセル・払戻 </span>
        が可能です（所定の手数料がかかります）。
      </p>
    </div>
  )
}

// ---------------------------------------------------------------------------
// Step 5 — 完了（乗車券）
// ---------------------------------------------------------------------------

function DoneStep({
  reservationNo,
  departure,
  seatIds,
  board,
  alight,
  total,
}: {
  reservationNo: string
  departure: ReturnType<typeof findPlan>["departure"]
  seatIds: string[]
  board: Stop
  alight: Stop
  total: number
}) {
  return (
    <div className="flex flex-col items-stretch gap-5 pt-2">
      <div className="flex flex-col items-center gap-1 text-center">
        <Badge variant="success">予約完了</Badge>
        <h2 className="text-lg font-semibold text-foreground">ご予約ありがとうございます</h2>
        <p className="text-sm text-muted-foreground">乗車時にこのQRを乗務員へご提示ください。</p>
      </div>

      <TicketStub value={reservationNo} format="qr" codeLabel={`予約番号 ${reservationNo}`}>
        <div className="flex flex-col gap-2">
          <div className="flex items-center justify-between gap-2">
            <span className="text-sm font-semibold text-foreground">{departure.operator}</span>
            <Badge variant="secondary">{departure.daynight}</Badge>
          </div>
          <div className="flex items-center gap-2 text-base font-bold text-foreground">
            <span className="truncate">{board.name.replace(/（.*$/, "")}</span>
            <IconArrowRight className="size-4 shrink-0 text-muted-foreground" aria-hidden="true" />
            <span className="truncate">{alight.name.replace(/（.*$/, "")}</span>
          </div>
          <dl className="grid grid-cols-3 gap-2 text-center">
            <div>
              <dt className="text-[10px] text-muted-foreground">出発</dt>
              <dd className="text-sm font-semibold tabular-nums text-foreground">{board.time}</dd>
            </div>
            <div>
              <dt className="text-[10px] text-muted-foreground">座席</dt>
              <dd className="text-sm font-semibold tabular-nums text-foreground">{seatIds.join("・") || "—"}</dd>
            </div>
            <div>
              <dt className="text-[10px] text-muted-foreground">運賃</dt>
              <dd className="text-sm font-semibold tabular-nums text-foreground">{yen(total)}</dd>
            </div>
          </dl>
        </div>
      </TicketStub>

      <Button variant="outline" size="lg" className="min-h-11 justify-center" asChild>
        <a href="/highway-bus">最初からもう一度予約する</a>
      </Button>
    </div>
  )
}

// 高速バス座席予約 — domain data for バスタ新宿 → 大阪(梅田/なんば).
// Realistic Japanese express-bus content (operators / fares / coach layouts are
// representative, not a live timetable).

import type { Seat } from "@gunjo/ui"

/** A boarding (乗車地) or alighting (降車地) stop along the corridor. */
export interface Stop {
  id: string
  name: string
  /** 出発/到着時刻 at this stop, "HH:MM" (翌 = next day for 夜行). */
  time: string
  /** 翌日 (next-day arrival) flag for 夜行便. */
  nextDay?: boolean
  note?: string
}

export type PlanId = "yade-std4" | "yade-indep3" | "yade-premium2"

/** A seat-type 運賃プラン for a departure. Each carries its own coach layout. */
export interface Plan {
  id: PlanId
  /** プラン名 (4列スタンダード etc.). */
  name: string
  /** 列構成 short tag (4列 / 3列独立 / 2列). */
  rowTag: string
  conditions: string
  /** 大人運賃 (繁忙期前・割引前のベース運賃). */
  baseFare: number
  /** A short selling line (highlight). */
  highlight?: string
  /** Coach column layout — null = aisle gap. */
  columns: (string | null)[]
  /** Seats for this plan's coach. */
  seats: Seat[]
  /** Legend captions that are specific to this coach. */
  badges: string[]
}

/** A 便 (departure) — one bus, one OD pair, a set of plans. */
export interface Departure {
  id: string
  operator: string
  /** 便名 / 号 (○○エクスプレス 大阪○号). */
  service: string
  /** 昼行 / 夜行. */
  daynight: "昼行" | "夜行"
  depTime: string
  arrTime: string
  arrNextDay?: boolean
  /** 所要 (e.g. "8時間20分"). */
  duration: string
  /** Default plan to preselect. */
  defaultPlanId: PlanId
  plans: Plan[]
}

// ---- Seat attribute helpers -------------------------------------------------

/**
 * SeatMap's `type` is a single string folded into the a11y name + an info dot.
 * Coaches have richer attributes (女性専用 / トイレ付近 / 最前列 / 補助席), so we
 * compose them into one string here and carry the *primary* tag separately for
 * our own legend/colour layer.
 */
export type CoachAttr = "女性専用" | "トイレ付近" | "最前列" | "補助席" | "コンセント"

/** Build a SeatMap `type` string from coach attributes (joined for the SR name). */
export function attrLabel(attrs: CoachAttr[]): string | undefined {
  return attrs.length ? attrs.join("・") : undefined
}

// ---- 3列独立シート coach (夜行) ---------------------------------------------
// 1 + aisle + 1 + aisle + 1 — columns A / C / D. 12 rows = 36 seats.
// 前方(1-3列)は女性専用ゾーン、最後列付近にトイレ。

const indep3Columns: (string | null)[] = ["A", null, "C", null, "D"]

function indep3Seats(): Seat[] {
  const seats: Seat[] = []
  const occupied = new Set(["1A", "2C", "4D", "5A", "7C", "9D", "10A", "11C", "12D", "12A"])
  const held = new Set(["3C", "8A"])
  for (let row = 1; row <= 12; row++) {
    for (const col of ["A", "C", "D"]) {
      const id = `${row}${col}`
      const attrs: CoachAttr[] = []
      // 前方3列 = 女性専用ゾーン
      if (row <= 3) attrs.push("女性専用")
      // 最前列
      if (row === 1) attrs.push("最前列")
      // 最後列付近 = トイレ
      if (row >= 11) attrs.push("トイレ付近")
      // 全席コンセント付（夜行プレミアム的）
      attrs.push("コンセント")
      const position: Seat["position"] =
        col === "A" || col === "D" ? "window" : "aisle"
      seats.push({
        id,
        row,
        col,
        state: occupied.has(id) ? "occupied" : held.has(id) ? "held" : "available",
        position,
        type: attrLabel(attrs),
        // 女性専用ゾーンに +500 の指定なし、最前列のみ +500
        fee: row === 1 ? 500 : undefined,
      })
    }
  }
  return seats
}

// ---- 4列スタンダード coach (昼行) -------------------------------------------
// 2 + aisle + 2 — columns A B / C D. 11 rows. 最後列(11)は補助席含む。

const std4Columns: (string | null)[] = ["A", "B", null, "C", "D"]

function std4Seats(): Seat[] {
  const seats: Seat[] = []
  const occupied = new Set(["1A", "2D", "3B", "4C", "6A", "7D", "8B", "9C", "11A", "11D"])
  const held = new Set(["5C", "10B"])
  for (let row = 1; row <= 11; row++) {
    for (const col of ["A", "B", "C", "D"]) {
      const id = `${row}${col}`
      const attrs: CoachAttr[] = []
      if (row === 1) attrs.push("最前列")
      if (row >= 10) attrs.push("トイレ付近")
      if (row === 11) attrs.push("補助席")
      const position: Seat["position"] =
        col === "A" || col === "D" ? "window" : "aisle"
      seats.push({
        id,
        row,
        col,
        state: occupied.has(id) ? "occupied" : held.has(id) ? "held" : "available",
        position,
        type: attrLabel(attrs),
      })
    }
  }
  return seats
}

// ---- 2列プレミアム coach (夜行) ---------------------------------------------
// 1 + aisle + 1 — columns A / D. 10 rows = 20 seats. All 女性は左A列のみ設定可。

const premium2Columns: (string | null)[] = ["A", null, "D"]

function premium2Seats(): Seat[] {
  const seats: Seat[] = []
  const occupied = new Set(["1D", "3A", "5D", "8A", "10D", "10A"])
  const held = new Set(["6A"])
  for (let row = 1; row <= 10; row++) {
    for (const col of ["A", "D"]) {
      const id = `${row}${col}`
      const attrs: CoachAttr[] = ["コンセント"]
      if (row === 1) attrs.push("最前列")
      if (col === "A") attrs.push("女性専用")
      if (row >= 9) attrs.push("トイレ付近")
      seats.push({
        id,
        row,
        col,
        state: occupied.has(id) ? "occupied" : held.has(id) ? "held" : "available",
        position: "window",
        type: attrLabel(attrs),
        fee: row === 1 ? 1000 : undefined,
      })
    }
  }
  return seats
}

