export function findPlan(planId: PlanId): { departure: Departure; plan: Plan } {
  for (const d of departures) {
    const p = d.plans.find((pl) => pl.id === planId)
    if (p) return { departure: d, plan: p }
  }
  // Fallback to first.
  return { departure: departures[0], plan: departures[0].plans[0] }
}
